public static void main(Args _args)
{
    ETGAgreementConfirmationReportController controller = new ETGAgreementConfirmationReportController();

    // Set the report name and design
    controller.parmReportName(ssrsReportStr(ETGAgreementConfirmationReport, PrecisionDesign1));
    controller.parmArgs(_args);

    // Suppress the UI dialog if you want it to print directly without user prompt (optional)
    controller.parmShowDialog(false);

    controller.startOperation();
}

protected void prePromptModifyContract()
{
    ETGAgreementConfirmationReportContract contract;
    SalesAgreementHeaderHistory salesAgreementHeaderHistory;

    // Check for the History table instead of the regular header table
    if (this.parmArgs() && this.parmArgs().dataset() == tableNum(SalesAgreementHeaderHistory))
    {
        salesAgreementHeaderHistory = this.parmArgs().record();

        contract = this.parmReportContract().parmRdpContract() as ETGAgreementConfirmationReportContract;

        // Pass the RecId of the History record to the contract
        contract.parmSalesAgreementHeaderRecId(salesAgreementHeaderHistory.RecId);
    }
    else
    {
        warning("Controller did not receive the SalesAgreementHeaderHistory record.");
    }

    super();
}
